    assert parse_dsl(case1) == expected1

    # Test 2: Nested block
    case2 = "BLOCK { SET y = 20; SET z = 30; }"
    expected2 = {
        "type": "Block",
        "body": [
            {"type": "Assignment", "var": "y", "value": 20},
            {"type": "Assignment", "var": "z", "value": 30}
        ]
    }
    assert parse_dsl(case2) == expected2

